import React from 'react';
import {
    Container,
    Box,
    Typography,
    Card,
    CardContent,
    Button,
    Paper,
} from '@mui/material';
import { useHistory } from 'react-router-dom';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';
import AnalyticsIcon from '@mui/icons-material/Analytics';
import SecurityIcon from '@mui/icons-material/Security';
import Dashboard from '../components/Dashboard';

const Home: React.FC = () => {
    const history = useHistory();

    const features = [
        {
            icon: <CloudUploadIcon sx={{ fontSize: 48, color: '#667eea' }} />,
            title: 'Easy Upload',
            description: 'Upload CSV datasets with your network logs',
        },
        {
            icon: <AnalyticsIcon sx={{ fontSize: 48, color: '#764ba2' }} />,
            title: 'Smart Analysis',
            description: 'ML-powered intrusion detection and analysis',
        },
        {
            icon: <SecurityIcon sx={{ fontSize: 48, color: '#f093fb' }} />,
            title: 'Security Focus',
            description: 'Identify and classify security threats',
        },
    ];

    return (
        <Box sx={{ py: 8 }}>
            <Container maxWidth="lg">
                {/* Hero Section */}
                <Box
                    sx={{
                        mb: 8,
                        textAlign: 'center',
                        color: 'white',
                    }}
                >
                    <Typography
                        variant="h3"
                        component="h1"
                        sx={{
                            fontWeight: 'bold',
                            mb: 2,
                            textShadow: '0 2px 4px rgba(0,0,0,0.3)',
                        }}
                    >
                        Cybersecurity Intrusion Detection System
                    </Typography>
                    <Typography
                        variant="h6"
                        sx={{
                            mb: 4,
                            opacity: 0.95,
                            maxWidth: 600,
                            mx: 'auto',
                            textShadow: '0 1px 2px rgba(0,0,0,0.2)',
                        }}
                    >
                        Advanced machine learning-powered analysis to detect and classify network intrusions in real-time
                    </Typography>
                    <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center', flexWrap: 'wrap' }}>
                        <Button
                            variant="contained"
                            size="large"
                            onClick={() => history.push('/upload')}
                            sx={{
                                background: 'linear-gradient(90deg, #fff 0%, #f0f0f0 100%)',
                                color: '#667eea',
                                fontWeight: 'bold',
                                fontSize: '1rem',
                                px: 4,
                                '&:hover': { transform: 'scale(1.05)' },
                                transition: 'transform 0.3s',
                            }}
                        >
                            Get Started
                        </Button>
                        <Button
                            variant="outlined"
                            size="large"
                            onClick={() => history.push('/results')}
                            sx={{
                                borderColor: 'white',
                                color: 'white',
                                fontWeight: 'bold',
                                fontSize: '1rem',
                                px: 4,
                                '&:hover': { background: 'rgba(255,255,255,0.1)' },
                            }}
                        >
                            View Results
                        </Button>
                    </Box>
                </Box>

                {/* Features Section */}
                <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr', md: '1fr 1fr 1fr' }, gap: 4, mb: 8 }}>
                    {features.map((feature, index) => (
                        <Card
                            key={index}
                            sx={{
                                height: '100%',
                                background: 'rgba(255, 255, 255, 0.95)',
                                backdropFilter: 'blur(10px)',
                                border: '1px solid rgba(255, 255, 255, 0.3)',
                                transition: 'transform 0.3s, box-shadow 0.3s',
                                '&:hover': {
                                    transform: 'translateY(-8px)',
                                    boxShadow: '0 12px 40px rgba(0, 0, 0, 0.15)',
                                    },
                                }}
                            >
                                <CardContent sx={{ textAlign: 'center', pt: 4 }}>
                                    <Box sx={{ mb: 2 }}>{feature.icon}</Box>
                                    <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 1 }}>
                                        {feature.title}
                                    </Typography>
                                    <Typography variant="body2" color="text.secondary">
                                        {feature.description}
                                    </Typography>
                                </CardContent>
                            </Card>
                        ))}
                    </Box>

                {/* Dashboard Preview */}
                <Box sx={{ mb: 4 }}>
                    <Typography
                        variant="h5"
                        sx={{
                            color: 'white',
                            fontWeight: 'bold',
                            mb: 3,
                            textShadow: '0 1px 2px rgba(0,0,0,0.2)',
                        }}
                    >
                        System Overview
                    </Typography>
                    <Paper
                        sx={{
                            background: 'rgba(255, 255, 255, 0.98)',
                            backdropFilter: 'blur(10px)',
                            border: '1px solid rgba(255, 255, 255, 0.3)',
                            p: 4,
                        }}
                    >
                        <Dashboard />
                    </Paper>
                </Box>
            </Container>
        </Box>
    );
};

export default Home;
